import { 
  doc, 
  getDoc, 
  setDoc, 
  updateDoc, 
  collection, 
  addDoc, 
  query, 
  where, 
  getDocs, 
  runTransaction,
  increment,
  onSnapshot,
  limit
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { db } from './firebase.ts';
import { AppState, User, Transaction, TransactionType, TransactionStatus, UserPackage, HotWalletConfig } from './types.ts';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { generateUserWallet, checkUsdtDeposits, processUsdtWithdrawal } from './tronService.ts';

// Helper to create a new user profile in Firestore
export const createFirestoreUser = async (userId: string, email: string, refCode: string | undefined): Promise<User> => {
  try {
    const cleanRefCode = refCode ? refCode.trim().toUpperCase() : '';

    const userRef = doc(db, 'users', userId);
    const existingSnap = await getDoc(userRef);

    if (existingSnap.exists()) {
      const data = existingSnap.data() as User;

      if (!data.referredBy && cleanRefCode) {
        console.log(`Repairing user ${userId}: Linking to referrer ${cleanRefCode}`);
        await updateDoc(userRef, { referredBy: cleanRefCode });

        try {
          const refQuery = query(collection(db, 'users'), where('referralCode', '==', cleanRefCode), limit(1));
          const refSnap = await getDocs(refQuery);
          if (!refSnap.empty) {
            const referrerId = refSnap.docs[0].id;
            await updateDoc(doc(db, 'users', referrerId), {
              referralCount: increment(1)
            });
          }
        } catch (e) {
          console.warn("Could not increment referrer count during repair", e);
        }

        return { ...data, referredBy: cleanRefCode };
      }

      return data;
    }

    const wallet = await generateUserWallet();

    let isFirstUser = false;
    const isDevAdmin = email.toLowerCase().includes('admin');

    try {
      const configRef = doc(db, 'system', 'status');
      const configSnap = await getDoc(configRef);
      if (!configSnap.exists()) {
        await setDoc(configRef, { initialized: true, rootAdmin: userId });
        isFirstUser = true;
      }
    } catch (e) {
      console.warn("System config access limited by permissions. Defaulting to standard user flow.");
    }

    const newUser: User = {
      id: userId,
      email,
      referralCode: (email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000)).replace(/[^A-Z0-9]/g, ''),
      referredBy: cleanRefCode,
      usdtDepositAddress: wallet.address.base58,
      depositPrivateKey: wallet.privateKey,
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: isFirstUser || isDevAdmin, 
      referralCount: 0,
      referralEarnings: 0,
      welcomeBonus: 100 
    };

    await setDoc(userRef, newUser);

    if (cleanRefCode) {
      try {
        const refQuery = query(collection(db, 'users'), where('referralCode', '==', cleanRefCode), limit(1));
        const refSnap = await getDocs(refQuery);
        if (!refSnap.empty) {
          const referrerId = refSnap.docs[0].id;
          await updateDoc(doc(db, 'users', referrerId), {
            referralCount: increment(1)
          });
        }
      } catch (refError) {
        console.warn("Referral update skipped due to permission restrictions.", refError);
      }
    }

    return newUser;
  } catch (err) {
    console.error("Critical Profile Provisioning Error:", err);
    throw err;
  }
};

export const fetchAllUsersFirestore = async (): Promise<User[]> => {
  const querySnapshot = await getDocs(collection(db, 'users'));
  return querySnapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as User));
};

export const toggleUserAdminFirestore = async (userId: string, currentStatus: boolean) => {
  const userRef = doc(db, 'users', userId);
  await updateDoc(userRef, {
    isAdmin: !currentStatus
  });
};

export const syncUserDepositsFirestore = async (userId: string) => {
  const userRef = doc(db, 'users', userId);
  const userSnap = await getDoc(userRef);
  if (!userSnap.exists()) return;
  const user = userSnap.data() as User;

  const since = Date.now() - (24 * 60 * 60 * 1000);
  const deposits = await checkUsdtDeposits(user.usdtDepositAddress, since);

  for (const dep of deposits) {
    const q = query(collection(db, 'transactions'), where('txHash', '==', dep.hash));
    const existing = await getDocs(q);

    if (existing.empty) {
      await runTransaction(db, async (transaction) => {
        transaction.update(userRef, {
          capitalBalance: increment(dep.amount)
        });

        const txRef = doc(collection(db, 'transactions'));
        transaction.set(txRef, {
          id: txRef.id,
          userId,
          type: TransactionType.DEPOSIT,
          amount: dep.amount,
          status: TransactionStatus.COMPLETED,
          txHash: dep.hash,
          timestamp: dep.timestamp,
          description: `Confirmed TRC20 USDT Deposit.`
        });
      });
    }
  }
};

export const requestWithdrawalFirestore = async (userId: string, amount: number, address: string) => {
  const userRef = doc(db, 'users', userId);
  const userSnap = await getDoc(userRef);
  if (!userSnap.exists()) throw new Error("User profile not synced.");
  const userData = userSnap.data() as User;

  if (userData.profitBalance < amount) throw new Error("Insufficient profit balance for extraction.");

  const txRef = await addDoc(collection(db, 'transactions'), {
    userId,
    type: TransactionType.WITHDRAWAL,
    amount,
    status: TransactionStatus.PENDING,
    timestamp: Date.now(),
    description: `Withdrawal request to ${address}`
  });

  await updateDoc(userRef, {
    profitBalance: increment(-amount)
  });

  return txRef.id;
};

export const authorizeWithdrawalFirestore = async (txId: string, hotWallet: HotWalletConfig) => {
  const txRef = doc(db, 'transactions', txId);
  const txSnap = await getDoc(txRef);
  if (!txSnap.exists()) return;
  const txData = txSnap.data() as Transaction;

  const userRef = doc(db, 'users', txData.userId);
  const userSnap = await getDoc(userRef);
  const userData = userSnap.data() as User;

  const toAddress = userData.withdrawalAddress || txData.description.split(' ').pop() || '';

  try {
    const result = await processUsdtWithdrawal(hotWallet.privateKey, toAddress, txData.amount);

    await updateDoc(txRef, {
      status: TransactionStatus.COMPLETED,
      txHash: result.txHash,
      description: `TRC20 Withdrawal confirmed via Hot Wallet.`
    });

    return result.txHash;
  } catch (err: any) {
    await updateDoc(userRef, {
      profitBalance: increment(txData.amount)
    });
    await updateDoc(txRef, {
      status: TransactionStatus.REJECTED,
      description: `Blockchain Error: ${err.message}`
    });
    throw err;
  }
};

export const updateUserProfileFirestore = async (userId: string, data: Partial<User>) => {
  const userRef = doc(db, 'users', userId);
  await updateDoc(userRef, data);
};

export const purchasePackageFirestore = async (userId: string, pkgId: string) => {
  const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
  if (!pkg) return;

  const activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const currentPkgDoc = activePkgsSnap.empty ? null : activePkgsSnap.docs[0];

  const userRef = doc(db, 'users', userId);

  await runTransaction(db, async (transaction) => {
    const userSnap = await transaction.get(userRef);
    if (!userSnap.exists()) throw new Error("User does not exist!");
    const userData = userSnap.data() as User;

    let cost = pkg.minAmount;
    let isUpgrade = false;

    if (currentPkgDoc) {
      const currentData = currentPkgDoc.data() as UserPackage;

      if (currentData.packageId === pkgId) throw new Error("Plan is already active.");
      if (pkg.minAmount <= currentData.amount) throw new Error("Cannot downgrade to a lower tier.");

      cost = pkg.minAmount - currentData.amount;
      isUpgrade = true;
    }

    if (userData.capitalBalance < cost) throw new Error(`Insufficient balance. Required: ${cost.toFixed(2)} USDT`);

    transaction.update(userRef, {
      capitalBalance: increment(-cost)
    });

    if (isUpgrade && currentPkgDoc) {
      transaction.update(doc(db, 'activePackages', currentPkgDoc.id), {
        packageId: pkg.id,
        amount: pkg.minAmount,
        activatedAt: Date.now() 
      });

      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, {
        id: txRef.id,
        userId,
        type: TransactionType.DEPOSIT,
        amount: cost,
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Upgrade to ${pkg.name}`
      });
    } else {
      const activePkgRef = doc(collection(db, 'activePackages'));
      transaction.set(activePkgRef, {
        id: activePkgRef.id,
        packageId: pkg.id,
        amount: pkg.minAmount,
        activatedAt: Date.now(),
        isActive: true,
        totalEarned: 0,
        userId
      });
      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, {
        id: txRef.id,
        userId,
        type: TransactionType.DEPOSIT,
        amount: pkg.minAmount, 
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Node Activation: ${pkg.name}`
      });
    }
  });
};

export const processDailyRoiFirestore = async (settings: any) => {
  if (!settings.isRoiEnabled || settings.platformPaused) return;
  const activePkgsQuery = query(collection(db, 'activePackages'), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  for (const docSnap of activePkgsSnap.docs) {
    const ap = docSnap.data() as UserPackage;
    const pkg = INITIAL_PACKAGES.find(p => p.id === ap.packageId);
    if (!pkg) continue;
    const dailyPercent = settings.roiOverride || pkg.dailyRoi;
    const earnings = ap.amount * (dailyPercent / 100);
    await runTransaction(db, async (transaction) => {
      const userRef = doc(db, 'users', ap.userId);
      transaction.update(userRef, {
        profitBalance: increment(earnings),
        totalEarned: increment(earnings)
      });
      transaction.update(doc(db, 'activePackages', docSnap.id), {
        totalEarned: increment(earnings)
      });
      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, {
        id: txRef.id,
        userId: ap.userId,
        type: TransactionType.ROI,
        amount: earnings,
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Daily profit from ${pkg.name}`
      });
    });
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import LandingPage from './components/LandingPage.tsx'; 
import { ThemeProvider } from './ThemeContext.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [myReferrals, setMyReferrals] = useState<User[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const [showLanding, setShowLanding] = useState(true);
  const [processingPkgId, setProcessingPkgId] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
    } catch (err: any) {
      console.error("Manual provision failed");
      setAuthError(`Setup failed: ${err.message || 'Unknown error'}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;
    let unsubRefs: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();

      if (firebaseUser) {
        setIsLoading(true);
        setShowLanding(false);

        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');

            if (userData.referralCode) {
              const qRefs = query(collection(db, 'users'), where('referredBy', '==', userData.referralCode));
              unsubRefs = onSnapshot(qRefs, (snap) => {
                const refs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as User);
                setMyReferrals(refs);
              }, (err) => {
                console.warn("Referral sync issue");
              });
            }

          } else {
            console.log("No profile found. Waiting for provision.");
            setIsProvisioning(true);
            setIsLoading(false);
          }
        }, (err) => {
          console.error("Profile sync failure");
          setAuthError("Failed to load profile. Check connection.");
          setIsLoading(false);
        });

        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setMyReferrals([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
        setShowLanding(true);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      setAuthError(error.message);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      console.error("Registration Error");
      if (error.code === 'auth/email-already-in-use' || error.message?.includes('email-already-in-use')) {
        setAuthError('This email is already registered. Please log in instead.');
      } else {
        setAuthError(error.message || 'Registration failed');
      }
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setShowLanding(true);
    } catch (err: any) {
      console.error("Session termination error");
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request submitted. Waiting for approval.');
    } catch (err: any) {
      alert(err.message || 'Withdrawal failed');
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Deposit check complete. Your balance has been updated.');
    } catch (err: any) {
      alert('Sync Failed: ' + (err.message || 'Unknown error'));
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) return;

    setProcessingPkgId(pkgId);
    // Allow UI to update before potentially blocking confirm dialog
    await new Promise(r => setTimeout(r, 50));

    try {
      const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
      if (!pkg) throw new Error("Package not found");

      const currentActive = activePackages.find(p => p.isActive);
      let cost = pkg.minAmount;
      let action = "Deploy Node";

      if (currentActive) {
          if (currentActive.packageId === pkgId) {
            setProcessingPkgId(null);
            return; 
          }
          if (currentActive.amount >= pkg.minAmount) {
              alert("You cannot downgrade to a lower tier node.");
              setProcessingPkgId(null);
              return;
          }
          cost = pkg.minAmount - currentActive.amount;
          action = "Upgrade Node";
      }

      // Functional requirement: Check insufficient funds and redirect to wallet
      if (currentUser.capitalBalance < cost) {
        if (window.confirm(`Insufficient Balance. Required: ${cost.toFixed(2)} USDT. Go to wallet to deposit?`)) {
          setView('wallet');
        }
        setProcessingPkgId(null);
        return;
      }

      if (window.confirm(`${action}: ${pkg.name} for ${cost.toFixed(2)} USDT?`)) {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert(`${action} successful.`);
      }
    } catch (err: any) {
      // Fix: Avoid passing objects to alert to prevent circular JSON error
      const msg = err instanceof Error ? err.message : (typeof err === 'string' ? err : 'Transaction failed');
      alert(msg);
    } finally {
      setProcessingPkgId(null);
    }
  };

  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-app-border border-t-app-accent rounded-full animate-spin"></div>
