                            <div className="text-right">
                               <span className="text-[10px] px-2 py-0.5 border border-app-border font-black uppercase tracking-widest text-green-500">Active</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={displayUser} onUpdate={(data) => updateUserProfileFirestore(displayUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser: displayUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Daily rewards paid out successfully.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

const App: React.FC = () => (
  <ThemeProvider>
    <AppContent />
  </ThemeProvider>
);

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import LandingPage from './components/LandingPage.tsx'; 
import { ThemeProvider } from './ThemeContext.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [myReferrals, setMyReferrals] = useState<User[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const [showLanding, setShowLanding] = useState(true);
  const [processingPkgId, setProcessingPkgId] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
    } catch (err: any) {
      console.error("Manual provision failed");
      setAuthError(`Setup failed: ${err.message || 'Unknown error'}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;
    let unsubRefs: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();

      if (firebaseUser) {
        setIsLoading(true);
        setShowLanding(false);

        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');

            if (userData.referralCode) {
              const qRefs = query(collection(db, 'users'), where('referredBy', '==', userData.referralCode));
              unsubRefs = onSnapshot(qRefs, (snap) => {
                const refs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as User);
                setMyReferrals(refs);
              }, (err) => {
                console.warn("Referral sync issue");
              });
            }

          } else {
            console.log("No profile found. Waiting for provision.");
            setIsProvisioning(true);
            setIsLoading(false);
          }
        }, (err) => {
          console.error("Profile sync failure");
          setAuthError("Failed to load profile. Check connection.");
          setIsLoading(false);
        });

        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setMyReferrals([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
        setShowLanding(true);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      console.error("Login Error:", error);
      let errorMessage = "Login failed. Please try again.";

      if (error.code === 'auth/invalid-credential' || error.message?.includes('invalid-credential')) {
        errorMessage = "Invalid email or password. Please check your credentials.";
      } else if (error.code === 'auth/user-not-found') {
        errorMessage = "No account found with this email. Please register.";
      } else if (error.code === 'auth/wrong-password') {
        errorMessage = "Incorrect password.";
      } else if (error.code === 'auth/too-many-requests') {
        errorMessage = "Too many failed attempts. Access temporarily blocked. Please try again later.";
      } else if (error.message) {
        errorMessage = error.message;
      }

      setAuthError(errorMessage);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      console.error("Registration Error");
      if (error.code === 'auth/email-already-in-use' || error.message?.includes('email-already-in-use')) {
        setAuthError('This email is already registered. Please log in instead.');
      } else {
        setAuthError(error.message || 'Registration failed');
      }
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setShowLanding(true);
    } catch (err: any) {
      console.error("Session termination error");
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request submitted. Waiting for approval.');
    } catch (err: any) {
      alert(err.message || 'Withdrawal failed');
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Deposit check complete. Your balance has been updated.');
    } catch (err: any) {
      alert('Sync Failed: ' + (err.message || 'Unknown error'));
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) return;

    setProcessingPkgId(pkgId);
    // Allow UI to update before potentially blocking confirm dialog
    await new Promise(r => setTimeout(r, 50));

    try {
      const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
      if (!pkg) throw new Error("Package not found");

      const currentActive = activePackages.find(p => p.isActive);
      let cost = pkg.minAmount;
      let action = "Deploy Node";

      if (currentActive) {
          if (currentActive.packageId === pkgId) {
            setProcessingPkgId(null);
            return; 
          }
          if (currentActive.amount >= pkg.minAmount) {
              alert("You cannot downgrade to a lower tier node.");
              setProcessingPkgId(null);
              return;
          }
          cost = pkg.minAmount - currentActive.amount;
          action = "Upgrade Node";
      }

      // Functional requirement: Check insufficient funds and redirect to wallet
      if (currentUser.capitalBalance < cost) {
        if (window.confirm(`Insufficient Balance. Required: ${cost.toFixed(2)} USDT. Go to wallet to deposit?`)) {
          setView('wallet');
        }
        setProcessingPkgId(null);
        return;
      }

      if (window.confirm(`${action}: ${pkg.name} for ${cost.toFixed(2)} USDT?`)) {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert(`${action} successful.`);
      }
    } catch (err: any) {
      // Fix: Avoid passing objects to alert to prevent circular JSON error
      const msg = err instanceof Error ? err.message : (typeof err === 'string' ? err : 'Transaction failed');
      alert(msg);
    } finally {
      setProcessingPkgId(null);
    }
  };

  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-app-border border-t-app-accent rounded-full animate-spin"></div>
          <div className="text-center space-y-4 max-w-xs">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted animate-pulse">
              {isProvisioning ? 'Creating Account...' : 'Loading...'}
            </p>
            {authError && <p className="text-[9px] text-red-500 font-bold uppercase tracking-widest">{authError}</p>}
            {isProvisioning && (
              <div className="flex flex-col gap-4 pt-8">
                 <button 
                  onClick={handleManualProvision}
                  className="px-6 py-2 border border-app-border text-[8px] font-black uppercase tracking-widest text-app-muted hover:text-app-text hover:border-app-text transition-all"
                >
                  Retry Setup
                </button>
                <button 
                  onClick={handleLogout}
                  className="text-[8px] font-black uppercase tracking-widest text-app-muted/50 hover:text-app-text transition-colors"
                >
                  Cancel
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  const displayUser = currentUser ? {
    ...currentUser,
    referralCount: myReferrals.length
  } : null;

  if (!displayUser) {
    if (showLanding) {
      return (
        <LandingPage 
          onLogin={() => {
            setAuthMode('login');
            setShowLanding(false);
          }} 
          onRegister={() => {
            setAuthMode('register');
            setShowLanding(false);
          }} 
        />
      );
    }

    return (
      <div className="min-h-screen bg-app-bg flex flex-col lg:flex-row relative transition-colors duration-300">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-app-border">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setShowLanding(true)}>
             <div className="w-8 h-8 bg-app-accent"></div>
             <span className="text-2xl font-black uppercase tracking-tighter text-app-text">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase text-app-text"
            >
              Start <br/> <span className="text-app-muted">Earning.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-app-muted leading-relaxed">
              Professional USDT Staking Platform. Simple, secure, and profitable.
            </p>
          </div>
          <div className="flex gap-16">
            <button 
              onClick={() => setShowLanding(true)}
              className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors"
            >
              <i className="fa-solid fa-arrow-left"></i>
              Back to Home
            </button>
          </div>
        </div>
        <div className="w-full lg:w-[35%] min-h-screen bg-app-bg flex items-center justify-center p-12 lg:p-24 transition-colors duration-300">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-sm space-y-12">
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted mb-2">Welcome</h2>
              <p className="text-2xl font-bold tracking-tight text-app-text">{authMode === 'login' ? 'Log In' : 'Create Account'}</p>
            </div>
            {authError && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-bold uppercase tracking-widest">
                {authError}
              </div>
            )}
            <form className="space-y-8" onSubmit={authMode === 'login' ? handleLogin : handleRegister}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Email</p>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="name@email.com" />
              </div>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Password</p>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="••••••••" />
              </div>
              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Referral Code (Optional)</p>
                  <input type="text" value={refCode} onChange={(e) => setRefCode(e.target.value.toUpperCase())} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-mono text-xs uppercase text-app-text placeholder:text-app-muted/30" placeholder="CODE" />
                </div>
              )}
              <button type="submit" disabled={isLoading} className="w-full py-5 bg-app-accent text-app-accent-text text-xs font-black uppercase tracking-[0.3em] hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center gap-4">
                {isLoading ? <div className="w-4 h-4 border-2 border-app-accent-text/20 border-t-app-accent-text rounded-full animate-spin"></div> : (authMode === 'login' ? 'Log In' : 'Sign Up')}
              </button>
              <div className="text-center pt-4">
                 <button type="button" onClick={() => { setAuthMode(authMode === 'login' ? 'register' : 'login'); setAuthError(null); }} className="text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors">{authMode === 'login' ? "Create an Account" : "Back to Login"}</button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={displayUser} onLogout={handleLogout} onNavigate={setView} currentView={view}>
      <AnimatePresence mode="wait">
        <motion.div key={view} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.3 }} className="pb-24 lg:pb-0">
          {view === 'dashboard' && <Dashboard user={displayUser} transactions={transactions} activePackages={activePackages} />}
          {view === 'wallet' && <Wallet user={displayUser} onDepositSim={handleDepositSync} onWithdrawRequest={handleWithdrawal} />}
          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none text-app-text">Liquidity<br/>Nodes.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-app-muted max-w-xl">Rent high-performance computing power to generate USDT.</p>
               </div>
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-app-border">
                 {INITIAL_PACKAGES.map((pkg) => {
                   const currentActive = activePackages.find(ap => ap.isActive);
                   const isCurrent = currentActive?.packageId === pkg.id;

                   let isDisabled = false;
                   let buttonText = "Deploy Node";
                   let extraInfo = "";

                   if (currentActive) {
                      if (isCurrent) {
                          buttonText = "Node Active";
                          isDisabled = true;
                      } else if (pkg.minAmount <= currentActive.amount) {
                          buttonText = "Unavailable";
                          isDisabled = true;
                          extraInfo = "Downgrade not allowed";
                      } else {
                          const upgradeCost = pkg.minAmount - currentActive.amount;
                          buttonText = `Upgrade Node`;
                          extraInfo = `Pay Difference: ${upgradeCost.toFixed(0)} USDT`;
                      }
                   }

                   const isProcessing = processingPkgId === pkg.id;

                   return (
                     <div key={pkg.id} className={`border-r border-b border-app-border p-6 md:p-12 group transition-all duration-500 ${isDisabled ? 'opacity-50 grayscale' : 'hover:bg-app-accent hover:text-app-accent-text'}`}>
                       <div className="space-y-4 md:space-y-8 h-full flex flex-col">
                         <div className="flex justify-between items-start">
                           <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em]">{pkg.name}</h3>
                           {isCurrent && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-green-500 text-white">Online</span>}
                         </div>
                         <div className="space-y-1">
                           <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">{pkg.dailyRoi}%</p>
                           <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Daily Yield</p>
                         </div>
                         <p className="text-[10px] md:text-sm font-medium leading-tight opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-app-border group-hover:border-app-accent-text/10">
                             <span className="text-[8px] font-bold uppercase opacity-60">Lease Cost</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handlePurchase(pkg.id);
                            }} 
                            disabled={isDisabled || isProcessing}
                            className="w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-app-border group-hover:bg-app-accent-text group-hover:text-app-accent group-hover:border-app-accent-text disabled:cursor-not-allowed flex items-center justify-center gap-2"
                           >
                            {isProcessing && <div className="w-3 h-3 border-2 border-current border-t-transparent rounded-full animate-spin"></div>}
                            {buttonText}
                           </button>
                           {extraInfo && <p className="text-[9px] font-bold uppercase text-center opacity-70">{extraInfo}</p>}
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">Referral<br/>Program.</h1>
                    <p className="serif italic text-2xl text-app-muted max-w-xl">Earn rewards by inviting friends to the platform.</p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-app-accent text-app-accent-text space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest">Your Invite Code</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{displayUser.referralCode}</p>
                    <button onClick={() => { navigator.clipboard.writeText(displayUser.referralCode); alert('Code copied to clipboard.'); }} className="w-full py-3 bg-app-accent-text text-app-accent text-[10px] font-black uppercase tracking-[0.2em]">Copy Code</button>
                  </div>
               </div>

               <div className="space-y-8">
                  <div className="flex items-center justify-between border-b border-app-border pb-4">
                    <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">My Downline</h2>
                    <span className="text-[10px] font-bold text-app-muted uppercase tracking-widest">{myReferrals.length} Partners</span>
                  </div>
                  <div className="border border-app-border bg-app-bg">
                    {myReferrals.length === 0 ? (
                      <div className="p-20 text-center opacity-20 serif italic text-app-muted">
                        No partners yet. Share your code to start growing your network.
                      </div>
                    ) : (
                      <div className="grid grid-cols-1 divide-y divide-app-border">
                        {myReferrals.map((refUser, idx) => (
                          <div key={refUser.id} className="p-6 flex items-center justify-between hover:bg-app-surface transition-colors">
                            <div className="flex items-center gap-6">
                               <span className="text-[10px] mono text-app-muted">{(idx + 1).toString().padStart(2, '0')}</span>
                               <div className="space-y-1">
                                  <p className="text-sm font-bold text-app-text">{refUser.email}</p>
                                  <p className="text-[10px] mono text-app-muted opacity-50">ID: {refUser.id.slice(0,6).toUpperCase()}</p>
                               </div>
                            </div>
                            <div className="text-right">
                               <span className="text-[10px] px-2 py-0.5 border border-app-border font-black uppercase tracking-widest text-green-500">Active</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={displayUser} onUpdate={(data) => updateUserProfileFirestore(displayUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser: displayUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Daily rewards paid out successfully.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

const App: React.FC = () => (
  <ThemeProvider>
    <AppContent />
  </ThemeProvider>
);

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import LandingPage from './components/LandingPage.tsx'; 
import { ThemeProvider } from './ThemeContext.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [myReferrals, setMyReferrals] = useState<User[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const [showLanding, setShowLanding] = useState(true);
  const [processingPkgId, setProcessingPkgId] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
    } catch (err: any) {
      console.error("Manual provision failed");
      const msg = err?.message || 'Unknown error';
      setAuthError(`Setup failed: ${msg}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;
    let unsubRefs: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();

      if (firebaseUser) {
        setIsLoading(true);
        setShowLanding(false);

        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');

            if (userData.referralCode) {
              const qRefs = query(collection(db, 'users'), where('referredBy', '==', userData.referralCode));
              unsubRefs = onSnapshot(qRefs, (snap) => {
                const refs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as User);
                setMyReferrals(refs);
              }, (err) => {
                console.warn("Referral sync issue");
              });
            }

          } else {
            console.log("No profile found. Waiting for provision.");
            setIsProvisioning(true);
            setIsLoading(false);
          }
        }, (err) => {
          console.error("Profile sync failure");
          setAuthError("Failed to load profile. Check connection.");
          setIsLoading(false);
        });

        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setMyReferrals([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
        setShowLanding(true);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      const msg = error?.message || "Auth failed";
      console.error("Login Error:", msg);

      let errorMessage = "Login failed. Please try again.";

      if (error.code === 'auth/invalid-credential' || msg.includes('invalid-credential')) {
        errorMessage = "Invalid email or password. Please check your credentials.";
      } else if (error.code === 'auth/user-not-found') {
        errorMessage = "No account found with this email. Please register.";
      } else if (error.code === 'auth/wrong-password') {
        errorMessage = "Incorrect password.";
      } else if (error.code === 'auth/too-many-requests') {
        errorMessage = "Too many failed attempts. Access temporarily blocked. Please try again later.";
      } else if (msg) {
        errorMessage = msg;
      }

      setAuthError(errorMessage);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      const msg = error?.message || "Unknown error";
      console.error("Registration Error:", msg);

      if (error.code === 'auth/email-already-in-use' || msg.includes('email-already-in-use')) {
        setAuthError('This email is already registered. Please log in instead.');
      } else {
        setAuthError(msg || 'Registration failed');
      }
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setShowLanding(true);
    } catch (err: any) {
      console.error("Session termination error");
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request submitted. Waiting for approval.');
    } catch (err: any) {
      alert(err?.message || 'Withdrawal failed');
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Deposit check complete. Your balance has been updated.');
    } catch (err: any) {
      alert('Sync Failed: ' + (err?.message || 'Unknown error'));
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) return;

    setProcessingPkgId(pkgId);
    // Allow UI to update before potentially blocking confirm dialog
    await new Promise(r => setTimeout(r, 50));

    try {
      const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
      if (!pkg) throw new Error("Package not found");

      const currentActive = activePackages.find(p => p.isActive);
      let cost = pkg.minAmount;
      let action = "Deploy Node";

      if (currentActive) {
          if (currentActive.packageId === pkgId) {
            setProcessingPkgId(null);
            return; 
          }
          if (currentActive.amount >= pkg.minAmount) {
              alert("You cannot downgrade to a lower tier node.");
              setProcessingPkgId(null);
              return;
          }
          cost = pkg.minAmount - currentActive.amount;
          action = "Upgrade Node";
      }

      // Functional requirement: Check insufficient funds and redirect to wallet
      if (currentUser.capitalBalance < cost) {
        if (window.confirm(`Insufficient Balance. Required: ${cost.toFixed(2)} USDT. Go to wallet to deposit?`)) {
          setView('wallet');
        }
        setProcessingPkgId(null);
        return;
      }

      if (window.confirm(`${action}: ${pkg.name} for ${cost.toFixed(2)} USDT?`)) {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert(`${action} successful.`);
      }
    } catch (err: any) {
      // Robust error handling to prevent circular JSON errors
      let msg = 'Transaction failed';
      if (err instanceof Error) {
        msg = err.message;
      } else if (typeof err === 'string') {
        msg = err;
      } else if (err && typeof err === 'object' && 'message' in err) {
        msg = String(err.message);
      }

      console.error("Purchase Error:", msg);
      alert(msg);
    } finally {
      setProcessingPkgId(null);
    }
  };

  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-app-border border-t-app-accent rounded-full animate-spin"></div>
          <div className="text-center space-y-4 max-w-xs">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted animate-pulse">
              {isProvisioning ? 'Creating Account...' : 'Loading...'}
            </p>
            {authError && <p className="text-[9px] text-red-500 font-bold uppercase tracking-widest">{authError}</p>}
            {isProvisioning && (
              <div className="flex flex-col gap-4 pt-8">
                 <button 
                  onClick={handleManualProvision}
                  className="px-6 py-2 border border-app-border text-[8px] font-black uppercase tracking-widest text-app-muted hover:text-app-text hover:border-app-text transition-all"
                >
                  Retry Setup
                </button>
                <button 
                  onClick={handleLogout}
                  className="text-[8px] font-black uppercase tracking-widest text-app-muted/50 hover:text-app-text transition-colors"
                >
                  Cancel
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  const displayUser = currentUser ? {
    ...currentUser,
    referralCount: myReferrals.length
  } : null;

  if (!displayUser) {
    if (showLanding) {
      return (
        <LandingPage 
          onLogin={() => {
            setAuthMode('login');
            setShowLanding(false);
          }} 
          onRegister={() => {
            setAuthMode('register');
            setShowLanding(false);
          }} 
        />
      );
    }

    return (
      <div className="min-h-screen bg-app-bg flex flex-col lg:flex-row relative transition-colors duration-300">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-app-border">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setShowLanding(true)}>
             <div className="w-8 h-8 bg-app-accent"></div>
             <span className="text-2xl font-black uppercase tracking-tighter text-app-text">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase text-app-text"
            >
              Start <br/> <span className="text-app-muted">Earning.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-app-muted leading-relaxed">
              Professional USDT Staking Platform. Simple, secure, and profitable.
            </p>
          </div>
          <div className="flex gap-16">
            <button 
              onClick={() => setShowLanding(true)}
              className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors"
            >
              <i className="fa-solid fa-arrow-left"></i>
              Back to Home
            </button>
          </div>
        </div>
        <div className="w-full lg:w-[35%] min-h-screen bg-app-bg flex items-center justify-center p-12 lg:p-24 transition-colors duration-300">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-sm space-y-12">
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted mb-2">Welcome</h2>
              <p className="text-2xl font-bold tracking-tight text-app-text">{authMode === 'login' ? 'Log In' : 'Create Account'}</p>
            </div>
            {authError && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-bold uppercase tracking-widest">
                {authError}
              </div>
            )}
            <form className="space-y-8" onSubmit={authMode === 'login' ? handleLogin : handleRegister}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Email</p>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="name@email.com" />
              </div>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Password</p>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="••••••••" />
              </div>
              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Referral Code (Optional)</p>
                  <input type="text" value={refCode} onChange={(e) => setRefCode(e.target.value.toUpperCase())} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-mono text-xs uppercase text-app-text placeholder:text-app-muted/30" placeholder="CODE" />
                </div>
              )}
              <button type="submit" disabled={isLoading} className="w-full py-5 bg-app-accent text-app-accent-text text-xs font-black uppercase tracking-[0.3em] hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center gap-4">
                {isLoading ? <div className="w-4 h-4 border-2 border-app-accent-text/20 border-t-app-accent-text rounded-full animate-spin"></div> : (authMode === 'login' ? 'Log In' : 'Sign Up')}
              </button>
              <div className="text-center pt-4">
                 <button type="button" onClick={() => { setAuthMode(authMode === 'login' ? 'register' : 'login'); setAuthError(null); }} className="text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors">{authMode === 'login' ? "Create an Account" : "Back to Login"}</button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={displayUser} onLogout={handleLogout} onNavigate={setView} currentView={view}>
      <AnimatePresence mode="wait">
        <motion.div key={view} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.3 }} className="pb-24 lg:pb-0">
          {view === 'dashboard' && <Dashboard user={displayUser} transactions={transactions} activePackages={activePackages} />}
          {view === 'wallet' && <Wallet user={displayUser} onDepositSim={handleDepositSync} onWithdrawRequest={handleWithdrawal} />}
          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none text-app-text">Liquidity<br/>Nodes.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-app-muted max-w-xl">Rent high-performance computing power to generate USDT.</p>
               </div>
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-app-border">
                 {INITIAL_PACKAGES.map((pkg) => {
                   const currentActive = activePackages.find(ap => ap.isActive);
                   const isCurrent = currentActive?.packageId === pkg.id;

                   let isDisabled = false;
                   let buttonText = "Deploy Node";
                   let extraInfo = "";

                   if (currentActive) {
                      if (isCurrent) {
                          buttonText = "Node Active";
                          isDisabled = true;
                      } else if (pkg.minAmount <= currentActive.amount) {
                          buttonText = "Unavailable";
                          isDisabled = true;
                          extraInfo = "Downgrade not allowed";
                      } else {
                          const upgradeCost = pkg.minAmount - currentActive.amount;
                          buttonText = `Upgrade Node`;
                          extraInfo = `Pay Difference: ${upgradeCost.toFixed(0)} USDT`;
                      }
                   }

                   const isProcessing = processingPkgId === pkg.id;

                   return (
                     <div key={pkg.id} className={`border-r border-b border-app-border p-6 md:p-12 group transition-all duration-500 ${isDisabled ? 'opacity-50 grayscale' : 'hover:bg-app-accent hover:text-app-accent-text'}`}>
                       <div className="space-y-4 md:space-y-8 h-full flex flex-col">
                         <div className="flex justify-between items-start">
                           <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em]">{pkg.name}</h3>
                           {isCurrent && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-green-500 text-white">Online</span>}
                         </div>
                         <div className="space-y-1">
                           <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">{pkg.dailyRoi}%</p>
                           <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Daily Yield</p>
                         </div>
                         <p className="text-[10px] md:text-sm font-medium leading-tight opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-app-border group-hover:border-app-accent-text/10">
                             <span className="text-[8px] font-bold uppercase opacity-60">Lease Cost</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handlePurchase(pkg.id);
                            }} 
                            disabled={isDisabled || isProcessing}
                            className="w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-app-border group-hover:bg-app-accent-text group-hover:text-app-accent group-hover:border-app-accent-text disabled:cursor-not-allowed flex items-center justify-center gap-2"
                           >
                            {isProcessing && <div className="w-3 h-3 border-2 border-current border-t-transparent rounded-full animate-spin"></div>}
                            {buttonText}
                           </button>
                           {extraInfo && <p className="text-[9px] font-bold uppercase text-center opacity-70">{extraInfo}</p>}
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">Referral<br/>Program.</h1>
                    <p className="serif italic text-2xl text-app-muted max-w-xl">Earn rewards by inviting friends to the platform.</p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-app-accent text-app-accent-text space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest">Your Invite Code</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{displayUser.referralCode}</p>
                    <button onClick={() => { navigator.clipboard.writeText(displayUser.referralCode); alert('Code copied to clipboard.'); }} className="w-full py-3 bg-app-accent-text text-app-accent text-[10px] font-black uppercase tracking-[0.2em]">Copy Code</button>
                  </div>
               </div>

               <div className="space-y-8">
                  <div className="flex items-center justify-between border-b border-app-border pb-4">
                    <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">My Downline</h2>
                    <span className="text-[10px] font-bold text-app-muted uppercase tracking-widest">{myReferrals.length} Partners</span>
                  </div>
                  <div className="border border-app-border bg-app-bg">
                    {myReferrals.length === 0 ? (
                      <div className="p-20 text-center opacity-20 serif italic text-app-muted">
                        No partners yet. Share your code to start growing your network.
                      </div>
                    ) : (
                      <div className="grid grid-cols-1 divide-y divide-app-border">
                        {myReferrals.map((refUser, idx) => (
                          <div key={refUser.id} className="p-6 flex items-center justify-between hover:bg-app-surface transition-colors">
                            <div className="flex items-center gap-6">
                               <span className="text-[10px] mono text-app-muted">{(idx + 1).toString().padStart(2, '0')}</span>
                               <div className="space-y-1">
                                  <p className="text-sm font-bold text-app-text">{refUser.email}</p>
                                  <p className="text-[10px] mono text-app-muted opacity-50">ID: {refUser.id.slice(0,6).toUpperCase()}</p>
                               </div>
                            </div>
                            <div className="text-right">
                               <span className="text-[10px] px-2 py-0.5 border border-app-border font-black uppercase tracking-widest text-green-500">Active</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={displayUser} onUpdate={(data) => updateUserProfileFirestore(displayUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser: displayUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Daily rewards paid out successfully.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

const App: React.FC = () => (
  <ThemeProvider>
    <AppContent />
  </ThemeProvider>
);

export default App;

import { 
  doc, 
  getDoc, 
  setDoc, 
  updateDoc, 
  collection, 
  addDoc, 
  query, 
  where, 
  getDocs, 
  runTransaction,
  increment,
  onSnapshot,
  limit
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { db } from './firebase.ts';
import { AppState, User, Transaction, TransactionType, TransactionStatus, UserPackage, HotWalletConfig } from './types.ts';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { generateUserWallet, checkUsdtDeposits, processUsdtWithdrawal } from './tronService.ts';

// Helper to create a new user profile in Firestore
export const createFirestoreUser = async (userId: string, email: string, refCode: string | undefined): Promise<User> => {
  try {
    const cleanRefCode = refCode ? refCode.trim().toUpperCase() : '';

    const userRef = doc(db, 'users', userId);
    const existingSnap = await getDoc(userRef);

    if (existingSnap.exists()) {
      const data = existingSnap.data() as User;

      if (!data.referredBy && cleanRefCode) {
        console.log(`Repairing user ${userId}: Linking to referrer ${cleanRefCode}`);
        await updateDoc(userRef, { referredBy: cleanRefCode });

        try {
          const refQuery = query(collection(db, 'users'), where('referralCode', '==', cleanRefCode), limit(1));
          const refSnap = await getDocs(refQuery);
          if (!refSnap.empty) {
            const referrerId = refSnap.docs[0].id;
            await updateDoc(doc(db, 'users', referrerId), {
              referralCount: increment(1)
            });
          }
        } catch (e) {
          console.warn("Could not increment referrer count during repair");
        }

        return { ...data, referredBy: cleanRefCode };
      }

      return data;
    }

    const wallet = await generateUserWallet();

    let isFirstUser = false;
    const isDevAdmin = email.toLowerCase().includes('admin');

    try {
      const configRef = doc(db, 'system', 'status');
      const configSnap = await getDoc(configRef);
      if (!configSnap.exists()) {
        await setDoc(configRef, { initialized: true, rootAdmin: userId });
        isFirstUser = true;
      }
    } catch (e) {
      console.warn("System config access limited by permissions. Defaulting to standard user flow.");
    }

    const newUser: User = {
      id: userId,
      email,
      referralCode: (email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000)).replace(/[^A-Z0-9]/g, ''),
      referredBy: cleanRefCode,
      usdtDepositAddress: wallet.address.base58,
      depositPrivateKey: wallet.privateKey,
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: isFirstUser || isDevAdmin, 
      referralCount: 0,
      referralEarnings: 0,
      welcomeBonus: 100 
    };

    await setDoc(userRef, newUser);

    if (cleanRefCode) {
      try {
        const refQuery = query(collection(db, 'users'), where('referralCode', '==', cleanRefCode), limit(1));
        const refSnap = await getDocs(refQuery);
        if (!refSnap.empty) {
          const referrerId = refSnap.docs[0].id;
          await updateDoc(doc(db, 'users', referrerId), {
            referralCount: increment(1)
          });
        }
      } catch (refError) {
        console.warn("Referral update skipped due to permission restrictions.");
      }
    }

    return newUser;
  } catch (err: any) {
    // Avoid logging complex error objects that might be circular
    console.error("Critical Profile Provisioning Error:", err.message || "Unknown error");
    throw err;
  }
};

export const fetchAllUsersFirestore = async (): Promise<User[]> => {
  const querySnapshot = await getDocs(collection(db, 'users'));
  return querySnapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as User));
};

export const toggleUserAdminFirestore = async (userId: string, currentStatus: boolean) => {
  const userRef = doc(db, 'users', userId);
  await updateDoc(userRef, {
    isAdmin: !currentStatus
  });
};

export const syncUserDepositsFirestore = async (userId: string) => {
  const userRef = doc(db, 'users', userId);
  const userSnap = await getDoc(userRef);
  if (!userSnap.exists()) return;
  const user = userSnap.data() as User;

  const since = Date.now() - (24 * 60 * 60 * 1000);
  const deposits = await checkUsdtDeposits(user.usdtDepositAddress, since);

  for (const dep of deposits) {
    const q = query(collection(db, 'transactions'), where('txHash', '==', dep.hash));
    const existing = await getDocs(q);

    if (existing.empty) {
      await runTransaction(db, async (transaction) => {
        transaction.update(userRef, {
          capitalBalance: increment(dep.amount)
        });

        const txRef = doc(collection(db, 'transactions'));
        transaction.set(txRef, {
          id: txRef.id,
          userId,
          type: TransactionType.DEPOSIT,
          amount: dep.amount,
          status: TransactionStatus.COMPLETED,
          txHash: dep.hash,
          timestamp: dep.timestamp,
          description: `Confirmed TRC20 USDT Deposit.`
        });
      });
    }
  }
};

export const requestWithdrawalFirestore = async (userId: string, amount: number, address: string) => {
  const userRef = doc(db, 'users', userId);
  const userSnap = await getDoc(userRef);
  if (!userSnap.exists()) throw new Error("User profile not synced.");
  const userData = userSnap.data() as User;

  if (userData.profitBalance < amount) throw new Error("Insufficient profit balance for extraction.");

  const txRef = await addDoc(collection(db, 'transactions'), {
    userId,
    type: TransactionType.WITHDRAWAL,
    amount,
    status: TransactionStatus.PENDING,
    timestamp: Date.now(),
    description: `Withdrawal request to ${address}`
  });

  await updateDoc(userRef, {
    profitBalance: increment(-amount)
  });

  return txRef.id;
};

export const authorizeWithdrawalFirestore = async (txId: string, hotWallet: HotWalletConfig) => {
  const txRef = doc(db, 'transactions', txId);
  const txSnap = await getDoc(txRef);
  if (!txSnap.exists()) return;
  const txData = txSnap.data() as Transaction;

  const userRef = doc(db, 'users', txData.userId);
  const userSnap = await getDoc(userRef);
  const userData = userSnap.data() as User;

  const toAddress = userData.withdrawalAddress || txData.description.split(' ').pop() || '';

  try {
    const result = await processUsdtWithdrawal(hotWallet.privateKey, toAddress, txData.amount);

    await updateDoc(txRef, {
      status: TransactionStatus.COMPLETED,
      txHash: result.txHash,
      description: `TRC20 Withdrawal confirmed via Hot Wallet.`
    });

    return result.txHash;
  } catch (err: any) {
    await updateDoc(userRef, {
      profitBalance: increment(txData.amount)
    });
    await updateDoc(txRef, {
      status: TransactionStatus.REJECTED,
      description: `Blockchain Error: ${err.message}`
    });
    throw err;
  }
};

export const updateUserProfileFirestore = async (userId: string, data: Partial<User>) => {
  const userRef = doc(db, 'users', userId);
  await updateDoc(userRef, data);
};

export const purchasePackageFirestore = async (userId: string, pkgId: string) => {
  const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
  if (!pkg) return;

  const activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const currentPkgDoc = activePkgsSnap.empty ? null : activePkgsSnap.docs[0];

  const userRef = doc(db, 'users', userId);

  await runTransaction(db, async (transaction) => {
    const userSnap = await transaction.get(userRef);
    if (!userSnap.exists()) throw new Error("User does not exist!");
    const userData = userSnap.data() as User;

    let cost = pkg.minAmount;
    let isUpgrade = false;

    if (currentPkgDoc) {
      const currentData = currentPkgDoc.data() as UserPackage;

      if (currentData.packageId === pkgId) throw new Error("Plan is already active.");
      if (pkg.minAmount <= currentData.amount) throw new Error("Cannot downgrade to a lower tier.");

      cost = pkg.minAmount - currentData.amount;
      isUpgrade = true;
    }

    if (userData.capitalBalance < cost) throw new Error(`Insufficient balance. Required: ${cost.toFixed(2)} USDT`);

    transaction.update(userRef, {
      capitalBalance: increment(-cost)
    });

    if (isUpgrade && currentPkgDoc) {
      transaction.update(doc(db, 'activePackages', currentPkgDoc.id), {
        packageId: pkg.id,
        amount: pkg.minAmount,
        activatedAt: Date.now() 
      });

      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, {
        id: txRef.id,
        userId,
        type: TransactionType.DEPOSIT,
        amount: cost,
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Upgrade to ${pkg.name}`
      });
    } else {
      const activePkgRef = doc(collection(db, 'activePackages'));
      transaction.set(activePkgRef, {
        id: activePkgRef.id,
        packageId: pkg.id,
        amount: pkg.minAmount,
        activatedAt: Date.now(),
        isActive: true,
        totalEarned: 0,
        userId
      });
      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, {
        id: txRef.id,
        userId,
        type: TransactionType.DEPOSIT,
        amount: pkg.minAmount, 
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Node Activation: ${pkg.name}`
      });
    }
  });
};

export const processDailyRoiFirestore = async (settings: any) => {
  if (!settings.isRoiEnabled || settings.platformPaused) return;
  const activePkgsQuery = query(collection(db, 'activePackages'), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  for (const docSnap of activePkgsSnap.docs) {
    const ap = docSnap.data() as UserPackage;
    const pkg = INITIAL_PACKAGES.find(p => p.id === ap.packageId);
    if (!pkg) continue;
    const dailyPercent = settings.roiOverride || pkg.dailyRoi;
    const earnings = ap.amount * (dailyPercent / 100);
    await runTransaction(db, async (transaction) => {
      const userRef = doc(db, 'users', ap.userId);
      transaction.update(userRef, {
        profitBalance: increment(earnings),
        totalEarned: increment(earnings)
      });
      transaction.update(doc(db, 'activePackages', docSnap.id), {
        totalEarned: increment(earnings)
      });
      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, {
        id: txRef.id,
        userId: ap.userId,
        type: TransactionType.ROI,
        amount: earnings,
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Daily profit from ${pkg.name}`
      });
    });
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import LandingPage from './components/LandingPage.tsx'; 
import { ThemeProvider } from './ThemeContext.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [myReferrals, setMyReferrals] = useState<User[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const [showLanding, setShowLanding] = useState(true);
  const [processingPkgId, setProcessingPkgId] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
    } catch (err: any) {
      console.error("Manual provision failed");
      const msg = err?.message || 'Unknown error';
      setAuthError(`Setup failed: ${msg}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;
    let unsubRefs: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();

      if (firebaseUser) {
        setIsLoading(true);
        setShowLanding(false);

        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');

            if (userData.referralCode) {
              const qRefs = query(collection(db, 'users'), where('referredBy', '==', userData.referralCode));
              unsubRefs = onSnapshot(qRefs, (snap) => {
                const refs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as User);
                setMyReferrals(refs);
              }, (err) => {
                console.warn("Referral sync issue");
              });
            }

          } else {
            console.log("No profile found. Waiting for provision.");
            setIsProvisioning(true);
            setIsLoading(false);
          }
        }, (err) => {
          console.error("Profile sync failure");
          setAuthError("Failed to load profile. Check connection.");
          setIsLoading(false);
        });

        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setMyReferrals([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
        setShowLanding(true);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      const msg = error?.message || "Auth failed";
      console.error("Login Error:", msg);

      let errorMessage = "Login failed. Please try again.";

      if (error.code === 'auth/invalid-credential' || msg.includes('invalid-credential')) {
        errorMessage = "Invalid email or password. Please check your credentials.";
      } else if (error.code === 'auth/user-not-found') {
        errorMessage = "No account found with this email. Please register.";
      } else if (error.code === 'auth/wrong-password') {
        errorMessage = "Incorrect password.";
      } else if (error.code === 'auth/too-many-requests') {
        errorMessage = "Too many failed attempts. Access temporarily blocked. Please try again later.";
      } else if (msg) {
        errorMessage = msg;
      }

      setAuthError(errorMessage);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      const msg = error?.message || "Unknown error";
      console.error("Registration Error:", msg);

      if (error.code === 'auth/email-already-in-use' || msg.includes('email-already-in-use')) {
        setAuthError('This email is already registered. Please log in instead.');
      } else {
        setAuthError(msg || 'Registration failed');
      }
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setShowLanding(true);
    } catch (err: any) {
      console.error("Session termination error");
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request submitted. Waiting for approval.');
    } catch (err: any) {
      alert(err?.message || 'Withdrawal failed');
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Deposit check complete. Your balance has been updated.');
    } catch (err: any) {
      alert('Sync Failed: ' + (err?.message || 'Unknown error'));
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) {
      alert("Session expired. Please log in again.");
      return;
    }

    setProcessingPkgId(pkgId);
    // Allow UI to update before blocking confirm dialog (Increased to 100ms)
    await new Promise(r => setTimeout(r, 100));

    try {
      const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
      if (!pkg) throw new Error("Package not found");

      const currentActive = activePackages.find(p => p.isActive);
      let cost = pkg.minAmount;
      let action = "Deploy Node";

      if (currentActive) {
          if (currentActive.packageId === pkgId) {
            alert("This node is already active.");
            setProcessingPkgId(null);
            return; 
          }
          if (currentActive.amount >= pkg.minAmount) {
              alert("You cannot downgrade to a lower tier node.");
              setProcessingPkgId(null);
              return;
          }
          cost = pkg.minAmount - currentActive.amount;
          action = "Upgrade Node";
      }

      // Functional requirement: Check insufficient funds and redirect to wallet
      if (currentUser.capitalBalance < cost) {
        const diff = cost - currentUser.capitalBalance;
        const confirmDeposit = window.confirm(
          `Insufficient Balance.\n\n` +
          `Required: ${cost.toFixed(2)} USDT\n` +
          `Balance: ${currentUser.capitalBalance.toFixed(2)} USDT\n` +
          `Missing: ${diff.toFixed(2)} USDT\n\n` +
          `Would you like to go to your wallet to deposit?`
        );

        if (confirmDeposit) {
          setView('wallet');
        }
        setProcessingPkgId(null);
        return;
      }

      const confirmPurchase = window.confirm(
        `${action}\n\n` +
        `Node: ${pkg.name}\n` +
        `Cost: ${cost.toFixed(2)} USDT\n\n` +
        `Proceed with deployment?`
      );

      if (confirmPurchase) {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert(`${action} successful! Your node is now generating yield.`);
      }
    } catch (err: any) {
      // Avoid passing objects to alert to prevent circular JSON error
      const msg = err instanceof Error ? err.message : (typeof err === 'string' ? err : 'Transaction failed');
      alert(`Error: ${msg}`);
    } finally {
      setProcessingPkgId(null);
    }
  };

  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-app-border border-t-app-accent rounded-full animate-spin"></div>
          <div className="text-center space-y-4 max-w-xs">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted animate-pulse">
              {isProvisioning ? 'Creating Account...' : 'Loading...'}
            </p>
            {authError && <p className="text-[9px] text-red-500 font-bold uppercase tracking-widest">{authError}</p>}
            {isProvisioning && (
              <div className="flex flex-col gap-4 pt-8">
                 <button 
                  onClick={handleManualProvision}
                  className="px-6 py-2 border border-app-border text-[8px] font-black uppercase tracking-widest text-app-muted hover:text-app-text hover:border-app-text transition-all"
                >
                  Retry Setup
                </button>
                <button 
                  onClick={handleLogout}
                  className="text-[8px] font-black uppercase tracking-widest text-app-muted/50 hover:text-app-text transition-colors"
                >
                  Cancel
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  const displayUser = currentUser ? {
    ...currentUser,
    referralCount: myReferrals.length
  } : null;

  if (!displayUser) {
    if (showLanding) {
      return (
        <LandingPage 
          onLogin={() => {
            setAuthMode('login');
            setShowLanding(false);
          }} 
          onRegister={() => {
            setAuthMode('register');
            setShowLanding(false);
          }} 
        />
      );
    }

    return (
      <div className="min-h-screen bg-app-bg flex flex-col lg:flex-row relative transition-colors duration-300">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-app-border">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setShowLanding(true)}>
             <div className="w-8 h-8 bg-app-accent"></div>
             <span className="text-2xl font-black uppercase tracking-tighter text-app-text">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase text-app-text"
            >
              Start <br/> <span className="text-app-muted">Earning.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-app-muted leading-relaxed">
              Professional USDT Staking Platform. Simple, secure, and profitable.
            </p>
          </div>
          <div className="flex gap-16">
            <button 
              onClick={() => setShowLanding(true)}
              className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors"
            >
              <i className="fa-solid fa-arrow-left"></i>
              Back to Home
            </button>
          </div>
        </div>
        <div className="w-full lg:w-[35%] min-h-screen bg-app-bg flex items-center justify-center p-12 lg:p-24 transition-colors duration-300">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-sm space-y-12">
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted mb-2">Welcome</h2>
              <p className="text-2xl font-bold tracking-tight text-app-text">{authMode === 'login' ? 'Log In' : 'Create Account'}</p>
            </div>
            {authError && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-bold uppercase tracking-widest">
                {authError}
              </div>
            )}
            <form className="space-y-8" onSubmit={authMode === 'login' ? handleLogin : handleRegister}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Email</p>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="name@email.com" />
              </div>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Password</p>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="••••••••" />
              </div>
              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Referral Code (Optional)</p>
                  <input type="text" value={refCode} onChange={(e) => setRefCode(e.target.value.toUpperCase())} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-mono text-xs uppercase text-app-text placeholder:text-app-muted/30" placeholder="CODE" />
                </div>
              )}
              <button type="submit" disabled={isLoading} className="w-full py-5 bg-app-accent text-app-accent-text text-xs font-black uppercase tracking-[0.3em] hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center gap-4">
                {isLoading ? <div className="w-4 h-4 border-2 border-app-accent-text/20 border-t-app-accent-text rounded-full animate-spin"></div> : (authMode === 'login' ? 'Log In' : 'Sign Up')}
              </button>
              <div className="text-center pt-4">
                 <button type="button" onClick={() => { setAuthMode(authMode === 'login' ? 'register' : 'login'); setAuthError(null); }} className="text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors">{authMode === 'login' ? "Create an Account" : "Back to Login"}</button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={displayUser} onLogout={handleLogout} onNavigate={setView} currentView={view}>
      <AnimatePresence mode="wait">
        <motion.div key={view} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.3 }} className="pb-24 lg:pb-0">
          {view === 'dashboard' && <Dashboard user={displayUser} transactions={transactions} activePackages={activePackages} />}
          {view === 'wallet' && <Wallet user={displayUser} onDepositSim={handleDepositSync} onWithdrawRequest={handleWithdrawal} />}
          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none text-app-text">Liquidity<br/>Nodes.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-app-muted max-w-xl">Rent high-performance computing power to generate USDT.</p>
               </div>
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-app-border">
                 {INITIAL_PACKAGES.map((pkg) => {
                   const currentActive = activePackages.find(ap => ap.isActive);
                   const isCurrent = currentActive?.packageId === pkg.id;

                   let isDisabled = false;
                   let buttonText = "Deploy Node";
                   let extraInfo = "";

                   if (currentActive) {
                      if (isCurrent) {
                          buttonText = "Node Active";
                          isDisabled = true;
                      } else if (pkg.minAmount <= currentActive.amount) {
                          buttonText = "Unavailable";
                          isDisabled = true;
                          extraInfo = "Downgrade not allowed";
                      } else {
                          const upgradeCost = pkg.minAmount - currentActive.amount;
                          buttonText = `Upgrade Node`;
                          extraInfo = `Pay Difference: ${upgradeCost.toFixed(0)} USDT`;
                      }
                   }

                   const isProcessing = processingPkgId === pkg.id;

                   return (
                     <div key={pkg.id} className={`border-r border-b border-app-border p-6 md:p-12 group transition-all duration-500 ${isDisabled ? 'opacity-50 grayscale' : 'hover:bg-app-accent hover:text-app-accent-text'}`}>
                       <div className="space-y-4 md:space-y-8 h-full flex flex-col">
                         <div className="flex justify-between items-start">
                           <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em]">{pkg.name}</h3>
                           {isCurrent && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-green-500 text-white">Online</span>}
                         </div>
                         <div className="space-y-1">
                           <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">{pkg.dailyRoi}%</p>
                           <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Daily Yield</p>
                         </div>
                         <p className="text-[10px] md:text-sm font-medium leading-tight opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-app-border group-hover:border-app-accent-text/10">
                             <span className="text-[8px] font-bold uppercase opacity-60">Lease Cost</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handlePurchase(pkg.id);
                            }} 
                            disabled={isDisabled || isProcessing}
                            className="w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-app-border group-hover:bg-app-accent-text group-hover:text-app-accent group-hover:border-app-accent-text disabled:cursor-not-allowed flex items-center justify-center gap-2"
                           >
                            {isProcessing && <div className="w-3 h-3 border-2 border-current border-t-transparent rounded-full animate-spin"></div>}
                            {buttonText}
                           </button>
                           {extraInfo && <p className="text-[9px] font-bold uppercase text-center opacity-70">{extraInfo}</p>}
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">Referral<br/>Program.</h1>
                    <p className="serif italic text-2xl text-app-muted max-w-xl">Earn rewards by inviting friends to the platform.</p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-app-accent text-app-accent-text space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest">Your Invite Code</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{displayUser.referralCode}</p>
                    <button onClick={() => { navigator.clipboard.writeText(displayUser.referralCode); alert('Code copied to clipboard.'); }} className="w-full py-3 bg-app-accent-text text-app-accent text-[10px] font-black uppercase tracking-[0.2em]">Copy Code</button>
                  </div>
               </div>

               <div className="space-y-8">
                  <div className="flex items-center justify-between border-b border-app-border pb-4">
                    <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">My Downline</h2>
                    <span className="text-[10px] font-bold text-app-muted uppercase tracking-widest">{myReferrals.length} Partners</span>
                  </div>
                  <div className="border border-app-border bg-app-bg">
                    {myReferrals.length === 0 ? (
                      <div className="p-20 text-center opacity-20 serif italic text-app-muted">
                        No partners yet. Share your code to start growing your network.
                      </div>
                    ) : (
                      <div className="grid grid-cols-1 divide-y divide-app-border">
                        {myReferrals.map((refUser, idx) => (
                          <div key={refUser.id} className="p-6 flex items-center justify-between hover:bg-app-surface transition-colors">
                            <div className="flex items-center gap-6">
                               <span className="text-[10px] mono text-app-muted">{(idx + 1).toString().padStart(2, '0')}</span>
                               <div className="space-y-1">
                                  <p className="text-sm font-bold text-app-text">{refUser.email}</p>
                                  <p className="text-[10px] mono text-app-muted opacity-50">ID: {refUser.id.slice(0,6).toUpperCase()}</p>
                               </div>
                            </div>
                            <div className="text-right">
                               <span className="text-[10px] px-2 py-0.5 border border-app-border font-black uppercase tracking-widest text-green-500">Active</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={displayUser} onUpdate={(data) => updateUserProfileFirestore(displayUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser: displayUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Daily rewards paid out successfully.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

const App: React.FC = () => (
  <ThemeProvider>
    <AppContent />
  </ThemeProvider>
);

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import LandingPage from './components/LandingPage.tsx'; 
import { ThemeProvider } from './ThemeContext.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [myReferrals, setMyReferrals] = useState<User[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const [showLanding, setShowLanding] = useState(true);
  const [processingPkgId, setProcessingPkgId] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
    } catch (err: any) {
      console.error("Manual provision failed");
      const msg = err?.message || 'Unknown error';
      setAuthError(`Setup failed: ${msg}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;
    let unsubRefs: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();

      if (firebaseUser) {
        setIsLoading(true);
        setShowLanding(false);

        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');

            if (userData.referralCode) {
              const qRefs = query(collection(db, 'users'), where('referredBy', '==', userData.referralCode));
              unsubRefs = onSnapshot(qRefs, (snap) => {
                const refs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as User);
                setMyReferrals(refs);
              }, (err) => {
                console.warn("Referral sync issue");
              });
            }

          } else {
            console.log("No profile found. Waiting for provision.");
            setIsProvisioning(true);
            setIsLoading(false);
          }
        }, (err) => {
          console.error("Profile sync failure");
          setAuthError("Failed to load profile. Check connection.");
          setIsLoading(false);
        });

        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setMyReferrals([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
        setShowLanding(true);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      const msg = error?.message || "Auth failed";
      console.error("Login Error:", msg);

      let errorMessage = "Login failed. Please try again.";

      if (error.code === 'auth/invalid-credential' || msg.includes('invalid-credential')) {
        errorMessage = "Invalid email or password. Please check your credentials.";
      } else if (error.code === 'auth/user-not-found') {
        errorMessage = "No account found with this email. Please register.";
      } else if (error.code === 'auth/wrong-password') {
        errorMessage = "Incorrect password.";
      } else if (error.code === 'auth/too-many-requests') {
        errorMessage = "Too many failed attempts. Access temporarily blocked. Please try again later.";
      } else if (msg) {
        errorMessage = msg;
      }

      setAuthError(errorMessage);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      const msg = error?.message || "Unknown error";

      if (error.code === 'auth/email-already-in-use' || msg.includes('email-already-in-use')) {
        setAuthError('This email is already registered. Please log in instead.');
      } else {
        console.error("Registration Error:", msg);
        setAuthError(msg || 'Registration failed');
      }
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setShowLanding(true);
    } catch (err: any) {
      console.error("Session termination error");
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request submitted. Waiting for approval.');
    } catch (err: any) {
      alert(err?.message || 'Withdrawal failed');
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Deposit check complete. Your balance has been updated.');
    } catch (err: any) {
      alert('Sync Failed: ' + (err?.message || 'Unknown error'));
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) {
      alert("Session expired. Please log in again.");
      return;
    }

    setProcessingPkgId(pkgId);
    // Allow UI to update before blocking confirm dialog (Increased to 100ms)
    await new Promise(r => setTimeout(r, 100));

    try {
      const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
      if (!pkg) throw new Error("Package not found");

      const currentActive = activePackages.find(p => p.isActive);
      let cost = pkg.minAmount;
      let action = "Deploy Node";

      if (currentActive) {
          if (currentActive.packageId === pkgId) {
            alert("This node is already active.");
            setProcessingPkgId(null);
            return; 
          }
          if (currentActive.amount >= pkg.minAmount) {
              alert("You cannot downgrade to a lower tier node.");
              setProcessingPkgId(null);
              return;
          }
          cost = pkg.minAmount - currentActive.amount;
          action = "Upgrade Node";
      }

      // Functional requirement: Check insufficient funds and redirect to wallet
      if (currentUser.capitalBalance < cost) {
        const diff = cost - currentUser.capitalBalance;
        const confirmDeposit = window.confirm(
          `Insufficient Balance.\n\n` +
          `Required: ${cost.toFixed(2)} USDT\n` +
          `Balance: ${currentUser.capitalBalance.toFixed(2)} USDT\n` +
          `Missing: ${diff.toFixed(2)} USDT\n\n` +
          `Would you like to go to your wallet to deposit?`
        );

        if (confirmDeposit) {
          setView('wallet');
        }
        setProcessingPkgId(null);
        return;
      }

      const confirmPurchase = window.confirm(
        `${action}\n\n` +
        `Node: ${pkg.name}\n` +
        `Cost: ${cost.toFixed(2)} USDT\n\n` +
        `Proceed with deployment?`
      );

      if (confirmPurchase) {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert(`${action} successful! Your node is now generating yield.`);
      }
    } catch (err: any) {
      // Avoid passing objects to alert to prevent circular JSON error
      const msg = err instanceof Error ? err.message : (typeof err === 'string' ? err : 'Transaction failed');
      alert(`Error: ${msg}`);
    } finally {
      setProcessingPkgId(null);
    }
  };

  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-app-border border-t-app-accent rounded-full animate-spin"></div>
          <div className="text-center space-y-4 max-w-xs">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted animate-pulse">
              {isProvisioning ? 'Creating Account...' : 'Loading...'}
            </p>
            {authError && <p className="text-[9px] text-red-500 font-bold uppercase tracking-widest">{authError}</p>}
            {isProvisioning && (
              <div className="flex flex-col gap-4 pt-8">
                 <button 
                  onClick={handleManualProvision}
                  className="px-6 py-2 border border-app-border text-[8px] font-black uppercase tracking-widest text-app-muted hover:text-app-text hover:border-app-text transition-all"
                >
                  Retry Setup
                </button>
                <button 
                  onClick={handleLogout}
                  className="text-[8px] font-black uppercase tracking-widest text-app-muted/50 hover:text-app-text transition-colors"
                >
                  Cancel
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  const displayUser = currentUser ? {
    ...currentUser,
    referralCount: myReferrals.length
  } : null;

  if (!displayUser) {
    if (showLanding) {
      return (
        <LandingPage 
          onLogin={() => {
            setAuthMode('login');
            setShowLanding(false);
          }} 
          onRegister={() => {
            setAuthMode('register');
            setShowLanding(false);
          }} 
        />
      );
    }

    return (
      <div className="min-h-screen bg-app-bg flex flex-col lg:flex-row relative transition-colors duration-300">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-app-border">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setShowLanding(true)}>
             <div className="w-8 h-8 bg-app-accent"></div>
             <span className="text-2xl font-black uppercase tracking-tighter text-app-text">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase text-app-text"
            >
              Start <br/> <span className="text-app-muted">Earning.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-app-muted leading-relaxed">
              Professional USDT Staking Platform. Simple, secure, and profitable.
            </p>
          </div>
          <div className="flex gap-16">
            <button 
              onClick={() => setShowLanding(true)}
              className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors"
            >
              <i className="fa-solid fa-arrow-left"></i>
              Back to Home
            </button>
          </div>
        </div>
