      alert('Sync Failed: ' + (err?.message || 'Unknown error'));
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) {
      alert("Session expired. Please log in again.");
      return;
    }

    setProcessingPkgId(pkgId);
    // Allow UI to update before blocking confirm dialog (Increased to 100ms)
    await new Promise(r => setTimeout(r, 100));

    try {
      const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
      if (!pkg) throw new Error("Package not found");

      const currentActive = activePackages.find(p => p.isActive);
      let cost = pkg.minAmount;
      let action = "Deploy Node";

      if (currentActive) {
          if (currentActive.packageId === pkgId) {
            alert("This node is already active.");
            setProcessingPkgId(null);
            return; 
          }
          if (currentActive.amount >= pkg.minAmount) {
              alert("You cannot downgrade to a lower tier node.");
              setProcessingPkgId(null);
              return;
          }
          cost = pkg.minAmount - currentActive.amount;
          action = "Upgrade Node";
      }

      // Functional requirement: Check insufficient funds and redirect to wallet
      if (currentUser.capitalBalance < cost) {
        const diff = cost - currentUser.capitalBalance;
        const confirmDeposit = window.confirm(
          `Insufficient Balance.\n\n` +
          `Required: ${cost.toFixed(2)} USDT\n` +
          `Balance: ${currentUser.capitalBalance.toFixed(2)} USDT\n` +
          `Missing: ${diff.toFixed(2)} USDT\n\n` +
          `Would you like to go to your wallet to deposit?`
        );

        if (confirmDeposit) {
          setView('wallet');
        }
        setProcessingPkgId(null);
        return;
      }

      const confirmPurchase = window.confirm(
        `${action}\n\n` +
        `Node: ${pkg.name}\n` +
        `Cost: ${cost.toFixed(2)} USDT\n\n` +
        `Proceed with deployment?`
      );

      if (confirmPurchase) {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert(`${action} successful! Your node is now generating yield.`);
      }
    } catch (err: any) {
      // Avoid passing objects to alert to prevent circular JSON error
      const msg = err instanceof Error ? err.message : (typeof err === 'string' ? err : 'Transaction failed');
      alert(`Error: ${msg}`);
    } finally {
      setProcessingPkgId(null);
    }
