Here are the complete Firestore Security Rules required to make your application function correctly.

These rules handle the specific requirements of your app:
1.  **Authentication**: Ensures users can only access their own data.
2.  **Admin Privileges**: Gives the admin full access to manage users, settings, and the hot wallet.
3.  **Referral System**: Allows the necessary queries to link users via referral codes.
4.  **Transactions**: allows the complex batch writes used in `store.ts` for purchasing packages and updating balances.

### Copy and Paste into Firestore Console -> Security Rules

```firestore
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // --- HELPER FUNCTIONS ---

    // Check if user is logged in
    function isAuthenticated() {
      return request.auth != null;
    }

    // Check if the user is accessing their own data
    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    // Check if the user is an Admin
    // This reads the user's document to check the 'isAdmin' boolean
    function isAdmin() {
      return isAuthenticated() &&
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) &&
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true;
    }

    // --- COLLECTION RULES ---

    // USERS COLLECTION
    match /users/{userId} {
      // READ: 
      // 1. Owner can read their own profile
      // 2. Admin can read any profile
      // 3. isAuthenticated() allows listing for referral code lookups (required for sign-up logic)
      allow get: if isOwner(userId) || isAdmin();
      allow list: if isAuthenticated();

      // CREATE:
      // Allow a user to create their own document during registration
      allow create: if isOwner(userId) || isAdmin();

      // UPDATE:
      // 1. Admin can update any user (for crediting balances, promoting roles)
      // 2. Owner can update their own data (required for: Buying packages (deducting balance), updating wallet address)
      allow update: if isOwner(userId) || isAdmin();
    }

    // TRANSACTIONS COLLECTION
    match /transactions/{txId} {
      // READ:
      // Owner can see their own txs, Admin can see all
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow list: if isAuthenticated(); // Broad list allowed to support query filtering by userId in App.tsx

      // CREATE:
      // Users create Withdrawal/Purchase records. Admin creates Credit records.
      allow create: if isAuthenticated();

      // UPDATE:
      // Only Admin can update transactions (e.g. changing status from PENDING to COMPLETED/REJECTED)
      allow update: if isAdmin();
    }

    // ACTIVE PACKAGES COLLECTION
    match /activePackages/{pkgId} {
      // READ: Owner or Admin
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow list: if isAuthenticated();

      // CREATE: User creates this when purchasing a node
      allow create: if isAuthenticated();

      // UPDATE: 
      // Admin updates this during ROI processing. 
      // User updates this if upgrading a node (via store.ts transaction)
      allow update: if isAuthenticated(); 
    }

    // SYSTEM SETTINGS (Global Config)
    match /system/settings {
      // Allow anyone to read settings (needed for maintenance mode check before login)
      allow get: if true;

      // Only Admin can change settings (ROI toggle, maintenance mode, etc)
      allow write: if isAdmin();
    }

    // SYSTEM STATUS (Initialization)
    match /system/status {
      allow read: if true;
      // Allow authenticated users to write only if trying to claim root admin on first launch
      allow write: if isAuthenticated();
    }

    // VAULT (Sensitive Hot Wallet Data)
    match /vault/hotwallet {
      // STRICTLY ADMIN ONLY
      // This protects the Private Key
      allow read, write: if isAdmin();
    }
  }
}

